import React, { useContext } from "react";
import { watchlist } from "../data/data"; // Ensure path is correct
import { GeneralContext } from "./GeneralContext";

// 1. Define the internal element for each row
const WatchListElement = ({ stock }) => {
  const { handleOpenBuyWindow } = useContext(GeneralContext);

  return (
    <li>
      <div className="item">
        <p className={stock.isUp ? "up" : "down"}>{stock.name}</p>
        <div className="item-info">
          <span className="percent">{stock.percent}</span>
          <span className="price">{stock.price}</span>
        </div>
      </div>
      <div className="actions">
        <span>
          <button
            className="buy"
            onClick={() => handleOpenBuyWindow(stock.name)}
          >
            Buy
          </button>
          <button className="action">Sell</button>
        </span>
      </div>
    </li>
  );
};

// 2. Define and DEFAULT EXPORT the main WatchList component
const WatchList = () => {
  return (
    <div className="watchlist-container">
      <div className="search-container">
        <input
          type="text"
          name="search"
          id="search"
          placeholder="Search eg: infy, bse"
          className="search"
        />
        <span className="counts"> {watchlist.length} / 50</span>
      </div>

      <ul className="list">
        {watchlist.map((stock, index) => {
          return <WatchListElement stock={stock} key={index} />;
        })}
      </ul>
    </div>
  );
};

export default WatchList;
